use std::cmp::Ordering;

// Helper function to check if sequence S is a cyclic shift of sequence B.
// Time complexity: O(k^2), where k is the length of the sequences.
fn is_cyclic_shift(b: &[i64], s: &[i64]) -> bool {
    let k = b.len();
    if k == 0 { return true; }
    if k != s.len() { return false; }

    // Case k=1: Cyclic shift does nothing, so B must equal S.
    if k == 1 {
        return b[0] == s[0];
    }

    // Check k possible rotations of B against S
    for j in 0..k {
        // Check if S matches B rotated left by j positions
        let mut is_match = true;
        for l in 0..k {
            // The l-th element of B rotated left by j comes from B[(l + j) % k]
            let b_idx = (l + j) % k;
            if s[l] != b[b_idx] {
                is_match = false;
                break;
            }
        }
        if is_match {
            return true;
        }
    }
    false
}

fn solve(nums: Vec<i64>) -> i64 {
    let n = nums.len();
    if n == 0 {
        return 0;
    }

    // 1. Get the fully sorted array S
    let mut sorted_nums = nums.clone();
    sorted_nums.sort_unstable();

    let mut total_sum = 0;

    // 2. Find all divisors k of N
    let mut divisors = Vec::new();
    let limit = (n as f64).sqrt() as usize;
    for i in 1..=limit {
        if n % i == 0 {
            divisors.push(i);
            if i * i != n {
                divisors.push(n / i);
            }
        }
    }

    // 3. Check each divisor k
    for &k_usize in &divisors {
        let k = k_usize;
        let mut is_sortable = true;

        // Check every block
        let num_blocks = n / k;
        for i in 0..num_blocks {
            let start = i * k;

            // Extract block Bi from nums
            let b_i = &nums[start..(start + k)];

            // Extract corresponding block Si from sorted_nums S
            let s_i = &sorted_nums[start..(start + k)];

            // Check if Si is a cyclic shift of Bi
            if !is_cyclic_shift(b_i, s_i) {
                is_sortable = false;
                break;
            }
        }

        if is_sortable {
            total_sum += k as i64;
        }
    }

    total_sum
}

